import{i as e}from"./authService-D0pVbikG.js";var t=e(`arrow-left`,[[`path`,{d:`m12 19-7-7 7-7`,key:`1l729n`}],[`path`,{d:`M19 12H5`,key:`x3x0zl`}]]),n={9:{Mathematics:{chapters:[{title:`Coordinate Geometry`,summary:`The structured framework for describing exact physical locations using numbers, with roots in the Sindhu-Sarasvatī Civilisation.`,flashcards:[{front:`What is the Origin?`,back:`The point of intersection of the x-axis and y-axis, with coordinates (0, 0).`},{front:`Baudhāyana-Pythagoras Theorem`,back:`Used to find the distance between any two points in the xy-plane.`},{front:`Distance Formula`,back:`√((x₂ - x₁)² + (y₂ - y₁)²) used to measure the shift between two coordinates.`},{front:`Quadrant II Signature`,back:`Negative x-coordinate and positive y-coordinate (-, +).`},{front:`Who formalised 'Zero'?`,back:`Brahmagupta (628 CE) formalised zero and negative numbers as algebraic entities.`}],qna:[{q:`What is the x-coordinate of a point on the y-axis?`,a:`The x-coordinate of any point on the y-axis is always 0.`},{q:`Does point Q(y, x) ever coincide with P(x, y)?`,a:`Yes, if and only if x = y.`},{q:`Who was the first to solve algebraic problems using geometry?`,a:`Ömar Khayyām (c. 1100 CE) interpreted algebraic problems in terms of coordinates in the plane.`}],keyIdeas:[`The Cartesian Plane is divided into four quadrants by the x and y axes.`,`Any point is represented as (x, y) where x is the abscissa and y is the ordinate.`,`The origin (0, 0) is the starting point for all measurements.`,`Points on the x-axis have y=0; points on the y-axis have x=0.`],formulas:[`Distance Formula: d = √((x₂ - x₁)² + (y₂ - y₁)²) - used for shift analysis.`]},{title:`Linear Polynomials`,summary:`Algebraic expressions of degree 1 that model linear growth and decay.`,flashcards:[{front:`Definition of a Linear Polynomial`,back:`A polynomial where the highest power of the variable (degree) is 1.`},{front:`Linear Relationship Form`,back:`Represented as y = ax + b, where 'a' is the slope and 'b' is the y-intercept.`},{front:`What does a negative slope indicate?`,back:`Linear decay, where a quantity decreases by a constant amount over equal intervals.`},{front:`The y-intercept`,back:`The point (0, b) where the straight line cuts the y-axis.`}],qna:[{q:`What is the degree of a constant polynomial like 8?`,a:`The degree is 0, as it can be written as 8x⁰.`},{q:`How is linear growth represented on a graph?`,a:`By a straight line with a positive slope.`},{q:`Who proposed the identity a² = (a+b)(a-b) + b²?`,a:`Śhrīdharāchārya (750 CE) as a method to quickly compute squares.`}],keyIdeas:[`A polynomial's degree is the highest power of its variable.`,`Linear polynomials have a degree of 1 (e.g., 3x + 5).`,`The zeroes of a polynomial are the values that make p(x) = 0.`,`Graphically, the zeroes are the x-intercepts of the function.`],formulas:[`General Form: p(x) = ax + b`,`Zero of p(x): x = -b/a`]},{title:`The World of Numbers`,summary:`The evolution of counting from tally marks on bones to the complex real number line.`,flashcards:[{front:`Ishango Bone Significance`,back:`A 20,000-year-old bone containing tally marks representing prime numbers (11, 13, 17, 19).`},{front:`Brahmagupta's Fortune/Debt Law`,back:`A debt times a debt is a fortune (- × - = +).`},{front:`Rational vs Irrational Decimals`,back:`Rational decimals terminate or repeat; irrational decimals are non-terminating and non-repeating.`},{front:`The Density Property`,back:`Between any two rational numbers, there are infinitely many more rational numbers.`}],qna:[{q:`Is √2 a rational number?`,a:`No, it is irrational. It cannot be expressed as a ratio p/q.`},{q:`What is Madhava's Infinite Series?`,a:`A series that unlocks the value of Pi (π) using an infinite sum of fractions.`},{q:`What is the absolute value of a rational number?`,a:`It represents its distance from 0 on the number line, always non-negative.`}],keyIdeas:[`Real numbers consist of Rational and Irrational numbers.`,`Rational numbers can be written as p/q (q ≠ 0) with terminating/repeating decimals.`,`Irrational numbers have non-terminating, non-repeating decimals.`,`Every real number corresponds to a unique point on the number line.`],formulas:[`Law of Exponents: a^m × a^n = a^(m+n)`,`Law of Exponents: (a^m)^n = a^(mn)`,`Rationalisation: To remove roots from denominator.`]},{title:`Algebraic Identities`,summary:`Mathematical rules for simplifying calculations and working with complex binomials/trinomials.`,flashcards:[{front:`(a + b + c)² Identity`,back:`a² + b² + c² + 2ab + 2bc + 2ca`},{front:`Identity vs Equation`,back:`An identity is true for ALL values of variables; an equation may only be true for specific values.`},{front:`(a + b)³ Expansion`,back:`a³ + 3a²b + 3ab² + b³`},{front:`Factorisation of x² - y²`,back:`(x + y)(x - y)`}],qna:[{q:`How can you visualize (a+b)² geometrically?`,a:`As a large square made of two smaller squares (a², b²) and two rectangles (ab).`},{q:`What is the identity for x³ + y³ + z³ - 3xyz?`,a:`(x + y + z)(x² + y² + z² - xy - xz - yz)`}],keyIdeas:[`Algebraic identities are true for all variable values.`,`Factoring is the reverse of expanding an identity.`,`Binomial expansions are used to solve complex multiplications quickly.`],formulas:[`(a + b)² = a² + 2ab + b²`,`(a - b)² = a² - 2ab + b²`,`(a + b)(a - b) = a² - b²`,`(x + a)(x + b) = x² + (a + b)x + ab`]},{title:`Circles`,summary:`The study of locus, chords, and the perfect symmetry of circular geometry.`,flashcards:[{front:`Definition of a Circle`,back:`The set of all points on a plane equidistant from a given point (the centre).`},{front:`What is a Chord?`,back:`A line segment connecting two points on a circle.`},{front:`The Diameter`,back:`A chord that passes through the centre of the circle.`}],qna:[{q:`What is the plural of axis?`,a:`Axes.`},{q:`What is the distance from the centre to any point on the circle called?`,a:`The radius.`}],keyIdeas:[`Equal chords of a circle subtend equal angles at the centre.`,`The perpendicular from the centre of a circle to a chord bisects the chord.`,`Chords equidistant from the centre of a circle are equal in length.`,`Angles in the same segment of a circle are equal.`],formulas:[`Circumference = 2πr`,`Area = πr²`]},{title:`Euclidean Geometry`,summary:`Introduction to the axioms and postulates that define flat-surface geometry.`,flashcards:[{front:`Euclid's 1st Postulate`,back:`A straight line segment can be drawn joining any two points.`},{front:`Axiom vs Postulate`,back:`Axioms are general truths; postulates are specific to geometry.`}],qna:[{q:`What is a point in Euclidean terms?`,a:`That which has no part.`}],keyIdeas:[`Geometry is based on unproven truths called Axioms and Postulates.`,`Axioms apply to all branches of math; Postulates are specific to geometry.`,`Things which are equal to the same thing are equal to one another.`],formulas:[`Postulate 1: A straight line joins any two points.`,`Postulate 4: All right angles are equal to one another.`]},{title:`Lines and Angles`,summary:`Properties of parallel lines, transversals, and angle relationships.`,flashcards:[{front:`Complementary Angles`,back:`Two angles whose sum is 90°.`},{front:`Supplementary Angles`,back:`Two angles whose sum is 180°.`}],qna:[{q:`What happens when a transversal intersects two parallel lines?`,a:`Corresponding angles are equal, and alternate interior angles are equal.`}],keyIdeas:[`Two lines are parallel if they never meet, no matter how far extended.`,`When two lines intersect, vertically opposite angles are equal.`,`The sum of angles of a triangle is always 180°.`],formulas:[`Supplementary Sum: ∠A + ∠B = 180°`,`Complementary Sum: ∠A + ∠B = 90°`]},{title:`Triangles & Quadrilaterals`,summary:`Comprehensive analysis of polygons and their congruence/similarity properties.`,flashcards:[{front:`SAS Congruence Rule`,back:`Side-Angle-Side: If two sides and the included angle of one triangle are equal to another.`},{front:`Parallelogram Property`,back:`Opposite sides are equal and opposite angles are equal.`}],qna:[{q:`What is the Angle Sum Property of a triangle?`,a:`The sum of the angles of a triangle is 180°.`}],keyIdeas:[`Congruent triangles are identical in shape and size.`,`Quadrilaterals have four sides, four angles, and four vertices.`,`In a parallelogram, diagonals bisect each other.`],formulas:[`Congruence Rules: SAS, ASA, SSS, RHS`,`Sum of angles in Quadrilateral = 360°`]},{title:`Heron's Formula`,summary:`Calculating the area of any triangle using its three sides and the semi-perimeter (s).`,flashcards:[{front:`Semi-perimeter (s)`,back:`Half the sum of the triangle's sides: s = (a + b + c) / 2.`},{front:`Heron's Formula`,back:`Area = √[s(s-a)(s-b)(s-c)]`}],qna:[{q:`When is Heron's Formula most useful?`,a:`When the height of the triangle is unknown, but all three sides are given.`}]},{title:`Surface Areas and Volumes`,summary:`The 3D geometry of cubes, cylinders, cones, and spheres for engineering and design.`,flashcards:[{front:`Volume of a Cylinder`,back:`V = πr²h`},{front:`Surface Area of a Sphere`,back:`A = 4πr²`},{front:`Volume of a Cone`,back:`V = (1/3)πr²h`}],qna:[{q:`How does volume change if the radius of a sphere is doubled?`,a:`The volume increases by 8 times (2³).`}]},{title:`Statistics`,summary:`The science of collecting, organizing, and interpreting data using mean, median, and mode.`,flashcards:[{front:`Mean`,back:`The average value, calculated by dividing the sum of observations by their count.`},{front:`Median`,back:`The middle-most value of an ordered data set.`},{front:`Mode`,back:`The value that appears most frequently in a data set.`}],qna:[{q:`What is the difference between primary and secondary data?`,a:`Primary data is collected directly by the researcher; secondary data is retrieved from existing records.`}],formulas:[`Mean = Σx / n`,`Median = (Middle value of sorted set)`]},{title:`Probability`,summary:`The mathematical study of chance and the likelihood of events occurring.`,flashcards:[{front:`Empirical Probability`,back:`P(E) = (Number of trials where E occurred) / (Total number of trials).`},{front:`Sure Event`,back:`An event with a probability of 1.`},{front:`Impossible Event`,back:`An event with a probability of 0.`}],qna:[{q:`What is the sum of probabilities of all elementary events in an experiment?`,a:`Exactly 1.`}]}]},Science:{chapters:[{title:`Science Exploration`,summary:`How observations lead to models, and how symbols like 'c' help us understand the universe.`,flashcards:[{front:`What is a Scientific Model?`,back:`A simplified way of looking at real systems that focuses only on what is most important.`},{front:`Why is 'c' used for speed of light?`,back:`It comes from the Latin word 'celeritas', meaning speed.`},{front:`Standard Unit of Mass`,back:`The Kilogram (kg), based on international agreements for fairness in daily life and trade.`},{front:`Meghnad Saha's Contribution`,back:`He simplified the study of stars by treating matter inside as a hot gas, connecting colour to temperature.`}],qna:[{q:`What happened in the airplane fuel miscalculation incident?`,a:`A flight ran out of fuel because ground crew used density in pounds (lb) instead of kilograms (kg), showing why SI units are critical.`},{q:`What is the difference between a Law and a Theory?`,a:`A Law describes a regular pattern (like Newton's Laws), whereas a Theory provides an explanation of WHY patterns occur (like Atomic Theory).`}],keyIdeas:[`Science is a process of wonder, observation, and measurement.`,`Units must be standardized (SI Units) to avoid errors in technology and trade.`,`Models are simplified representations used to understand complex phenomena.`,`Laws describe 'what' happens; Theories explain 'why' it happens.`]},{title:`Cell: The Building Block`,summary:`The fascinating world of cellular biology, from Robert Hooke's cork to the Fluid-Mosaic model.`,flashcards:[{front:`Robert Hooke (1665)`,back:`The first person to observe and name 'cells' while examining a thin slice of cork.`},{front:`Selectively Permeable Membrane`,back:`A boundary that allows some substances to pass through while blocking others.`},{front:`Osmosis`,back:`The diffusion of water across a selectively permeable membrane from higher to lower water concentration.`},{front:`Mitochondria`,back:`The 'Powerhouse of the cell' that stores energy in the form of ATP.`},{front:`Mitosis vs Meiosis`,back:`Mitosis produces 2 identical daughter cells; Meiosis produces 4 gametes with half the DNA.`}],qna:[{q:`What happens to a cell in a Hypertonic solution?`,a:`The solute concentration outside is higher than inside, causing the cell to lose water and shrink.`},{q:`Who proposed that 'all cells arise from pre-existing cells'?`,a:`Rudolf Virchow in 1855, expanding the Cell Theory.`},{q:`What is the role of the Golgi apparatus?`,a:`It acts as the cell's post office, modifying, sorting, and packaging proteins for transport.`}],keyIdeas:[`The cell is the basic structural and functional unit of life.`,`Plasma membrane is selectively permeable, controlling entry and exit.`,`Organelles like Mitochondria (energy) and Nucleus (DNA) have specific roles.`,`Plant cells have a cell wall and chloroplasts, which animal cells lack.`]},{title:`Tissues in Action`,summary:`How cells group together to form the engineering marvels of the human and plant body.`,flashcards:[{front:`Apical Meristem`,back:`Meristematic tissue located at root and shoot tips that helps plants grow in length.`},{front:`Xylem vs Phloem`,back:`Xylem transports water/minerals; Phloem transports food prepared in leaves.`},{front:`Ligament vs Tendon`,back:`Ligaments connect bone to bone; Tendons connect muscle to bone.`},{front:`Neuron structure`,back:`Consists of a cell body, dendrites (receive signals), and an axon (carries messages).`}],qna:[{q:`Why are plant and animal tissues different?`,a:`Plants are fixed (need support/rigidity) while animals move (need flexibility/locomotion).`},{q:`What are the three types of muscles?`,a:`Skeletal (voluntary), Smooth (involuntary), and Cardiac (heart specific, tireless).`}]},{title:`Describing Motion Around Us`,summary:`The simplest kind of motion: Linear and circular, described using position, distance, speed, velocity, and acceleration.`,flashcards:[{front:`Distance vs Displacement`,back:`Distance is the total path length; Displacement is the net change in position (magnitude and direction).`},{front:`Average Velocity`,back:`Displacement divided by the time interval (rate of change of position).`},{front:`Average Acceleration`,back:`The rate of change of velocity: (v - u) / t.`},{front:`Kinematic Equation 1 (Velocity)`,back:`v = u + at (Relates velocity, initial velocity, acceleration, and time).`},{front:`Kinematic Equation 2 (Position)`,back:`s = ut + ½at² (Calculates displacement under constant acceleration).`},{front:`Kinematic Equation 3 (Velocity-Position)`,back:`v² = u² + 2as (Relates final velocity to displacement without time).`},{front:`Uniform Circular Motion`,back:`Motion in a circular path with constant speed; velocity changes continuously due to direction.`}],qna:[{q:`When is displacement zero if distance is not zero?`,a:`When an object returns to its starting point after a journey (e.g., swimming a full lap).`},{q:`What does the slope of a position-time graph represent?`,a:`The magnitude of velocity (speed if moving in a straight line).`},{q:`What does the area under a velocity-time graph represent?`,a:`The displacement of the object over that time interval.`},{q:`What was the 'Aryabhatiya' contribution to motion?`,a:`Established that speed is distance divided by time as early as the 5th century CE.`}],keyIdeas:[`Motion is relative to a reference point (Origin).`,`Scalar quantities have only magnitude (Distance, Speed).`,`Vector quantities have magnitude and direction (Displacement, Velocity).`,`Acceleration is the change in velocity over time.`],formulas:[`v = u + at`,`s = ut + ½at²`,`v² = u² + 2as`]},{title:`Exploring Mixtures & Separation`,summary:`From industrial processes like sugar production to life-saving medical tests like ORS and blood analysis.`,flashcards:[{front:`Homogeneous vs Heterogeneous`,back:`Homogeneous (solutions) have uniform composition; Heterogeneous (suspensions) have visible, non-uniform particles.`},{front:`Concentration (% m/m)`,back:`(Mass of Solute / Mass of Solution) × 100.`},{front:`Crystallization`,back:`Separating a pure solid from a saturated solution by slow cooling (e.g., making candy sugar/mishri).`},{front:`Distillation`,back:`Separating miscible liquids with a boiling point difference of at least 25°C.`},{front:`Sublimation`,back:`The transition of a solid directly into a vapour without passing through the liquid state (e.g., camphor, naphthalene).`},{front:`Colloid`,back:`A mixture where particles (1-1000 nm) are uniformly dispersed and do not settle, showing the Tyndall effect.`},{front:`Tyndall Effect`,back:`The scattering of a beam of light by particles in a colloid or suspension, making the path visible.`}],qna:[{q:`Who developed the life-saving Oral Rehydration Solution (ORS)?`,a:`Indian paediatrician Dilip Mahalanabis, revolutionising treatment for dehydration.`},{q:`What is 'Mitti ka Ittar'?`,a:`A natural perfume from Kannauj produced using the traditional Deg-Bhapka distillation method.`},{q:`How does a paperfuge work?`,a:`A hand-powered centrifuge made from cardboard and string that can separate blood components in remote areas.`},{q:`What is the role of Alum (Fitkari) in water purification?`,a:`It acts as a coagulant, causing fine suspended particles to clump together and settle down.`}]},{title:`How Forces Affect Motion`,summary:`Investigating the causes of motion through Newton's three laws, balanced forces, and the friction matrix.`,flashcards:[{front:`Balanced vs Unbalanced Forces`,back:`Balanced forces result in zero net force (no change in motion); Unbalanced forces cause acceleration.`},{front:`Newton's First Law (Inertia)`,back:`An object resists changes to its state of rest or uniform motion unless acted on by a net force.`},{front:`Newton's Second Law Formula`,back:`F = ma (Force equals mass times acceleration).`},{front:`The Newton (N)`,back:`The force that produces an acceleration of 1 m/s² on a 1 kg mass.`},{front:`Newton's Third Law`,back:`To every action, there is an equal and opposite reaction (acting on different objects).`},{front:`Momentum`,back:`The product of an object's mass and its velocity (p = mv).`},{front:`Friction Direction`,back:`Always acts in a direction opposite to the direction of motion or intended motion.`}],qna:[{q:`Why did the Vikram lander fire its engines in the direction of motion?`,a:`To exert a force opposite to its velocity, slowing it down for a soft landing on the Moon (Newton's 3rd Law).`},{q:`What is 'Inertia'?`,a:`The inherent tendency of objects to resist any change in their state of rest or motion.`},{q:`How do airbags reduce injury in a car crash?`,a:`By increasing the time over which the velocity changes, thus reducing the magnitude of acceleration and the resulting force on the passenger.`},{q:`What happens if the net force on a moving object is zero?`,a:`The object continues to move with constant velocity in a straight line (Newton's 1st Law).`}],keyIdeas:[`Force is a push or pull that changes an object's state of motion.`,`Inertia depends on mass: more mass means more inertia.`,`Momentum is conserved in a system unless external forces act.`,`Friction is a contact force that opposes relative motion.`],formulas:[`F = ma`,`p = mv`,`Rate of change of momentum = Net Force`]},{title:`Work, Energy & Simple Machines`,summary:`Exploring the capacity to do work, conservation of mechanical energy, and the building blocks of everyday machines.`,flashcards:[{front:`Scientific Definition of Work`,back:`Work (W) = Force (F) × Displacement (s) in the direction of the force.`},{front:`Kinetic Energy Formula`,back:`K = ½mv² (Energy due to an object's motion).`},{front:`Potential Energy Formula`,back:`U = mgh (Energy stored due to an object's position or height).`},{front:`Conservation of Mechanical Energy`,back:`The sum of kinetic and potential energy remains constant in a system without external friction.`},{front:`Power (P)`,back:`The rate at which work is done (P = W / t), measured in Watts (W).`},{front:`Mechanical Advantage`,back:`The ratio of the Load (force to be overcome) to the Effort (force applied).`},{front:`Three Simple Machines`,back:`Pulley (changes force direction), Inclined Plane (reduces required force over distance), Lever (pivots on a fulcrum).`}],qna:[{q:`Is work done when you push a rigid wall?`,a:`No, because there is no displacement (s = 0), so work done is zero.`},{q:`What is a 'Gharat' or 'Panchakki'?`,a:`A traditional Himalayan water mill that converts the potential energy of flowing water into kinetic energy to grind grain.`},{q:`Why are roads on hills built in gentle slopes?`,a:`They act as long inclined planes; a longer path (L) requires less effort force (F) to reach the same height (h).`},{q:`What is Dark Energy?`,a:`A mysterious form of energy proposed by scientists to explain why the expansion of the Universe is accelerating.`}]},{title:`Journey Inside the Atom`,summary:`Exploring the subatomic realm from ancient Parmanu concepts to modern electron clouds and nuclear isotopes.`,flashcards:[{front:`Parmanu`,back:`The smallest indivisible particle of matter described by Acharya Kanada in the Vaisesika Sutras.`},{front:`Cathode Rays`,back:`Streams of negatively charged particles (electrons) discovered by J.J. Thomson.`},{front:`Plum Pudding Model`,back:`Thomson's model: An atom is a positive sphere with electrons embedded like seeds in a watermelon.`},{front:`Alpha Scattering Result`,back:`Most particles passed through, but some bounced back, proving the existence of a dense, tiny nucleus.`},{front:`Bohr's Shells (K, L, M, N)`,back:`Fixed energy levels where electrons revolve without losing energy (Stationary States).`},{front:`Valency`,back:`The combining capacity of an atom; determined by electrons lost, gained, or shared to complete an octet.`},{front:`Isotopes`,back:`Atoms of the same element with the same atomic number but different mass numbers (e.g., C-12, C-14).`}],qna:[{q:`Who is the Father of the Indian Nuclear Programme?`,a:`Homi Jehangir Bhabha, who established BARC and TIFR.`},{q:`Why is the mass of helium 4 times hydrogen if it only has 2 protons?`,a:`Because it also contains 2 neutrons, which contribute to mass but have no charge.`},{q:`What are isotopes used for in medicine?`,a:`Cobalt-60 is used for cancer treatment; Iodine-131 is used to treat goitre.`},{q:`What determines the identity of an element?`,a:`The Atomic Number (Z), which is the number of protons in its nucleus.`}]},{title:`Atomic Foundations of Matter`,summary:`The laws of chemical combination, the logic of bonding, and the architecture of molecules and ionic lattices.`,flashcards:[{front:`Law of Conservation of Mass`,back:`Matter can neither be created nor destroyed in a chemical reaction (Lavoisier, 1789).`},{front:`Law of Constant Proportions`,back:`In a compound, elements are always present in definite proportions by mass (Proust).`},{front:`Covalent Bond`,back:`A chemical bond formed by the sharing of electron pairs between atoms.`},{front:`Ionic Bond`,back:`The electrostatic force of attraction between oppositely charged ions (Cation and Anion).`},{front:`Polyatomic Ion`,back:`A cluster of atoms that behaves as a single unit and carries a fixed net charge (e.g., SO₄²⁻, NH₄⁺).`},{front:`Molecular Mass`,back:`The sum of the atomic masses of all atoms in a molecule (measured in unified mass unit 'u').`},{front:`Formula Unit Mass`,back:`Used for ionic compounds (which don't form single molecules) to represent the simplest whole-number ratio of ions.`}],qna:[{q:`Why does dissolved salt conduct electricity but sugar does not?`,a:`Salt (ionic) dissociates into free-moving ions in water; sugar (covalent) remains as neutral molecules.`},{q:`What is Cinnabar (Hingula)?`,a:`An ancient red pigment (Mercury Sulfide) that demonstrated constant proportions (86.22% Hg, 13.78% S) across civilisations.`},{q:`Who is known as the Father of Modern Chemistry?`,a:`Antoine Lavoisier, who proposed the Law of Conservation of Mass.`},{q:`What is the 'criss-cross' method?`,a:`A strategy for writing chemical formulae by crossing over the valencies/charges of combining ions.`}]},{title:`Sound Waves: Characteristics and Applications`,summary:`The physics of vibrations, the mechanics of longitudinal waves, and the technology of echolocation and SONAR.`,flashcards:[{front:`Longitudinal Wave`,back:`A wave where particles of the medium vibrate back and forth parallel to the direction of propagation.`},{front:`Compression (C)`,back:`A region in a longitudinal wave where the particles are closest together (high density/pressure).`},{front:`Rarefaction (R)`,back:`A region in a longitudinal wave where the particles are furthest apart (low density/pressure).`},{front:`Audible Range`,back:`The frequency range detectable by human ears, typically 20 Hz to 20,000 Hz.`},{front:`Ultrasonic vs Infrasonic`,back:`Ultrasonic is above 20 kHz (bats, medical imaging); Infrasonic is below 20 Hz (earthquakes, elephants).`},{front:`Echo Condition`,back:`To hear a distinct echo, the reflecting surface must be at least 17m away (0.1s time gap).`},{front:`SONAR`,back:`Sound Navigation and Ranging: Using ultrasonic waves to measure underwater depth or detect objects.`}],qna:[{q:`Why can't sound travel in a vacuum?`,a:`Sound is a mechanical wave that requires a material medium (solid, liquid, or gas) to transmit vibrations.`},{q:`How did C.V. Raman contribute to acoustics?`,a:`He studied the unique harmonic overtones produced by Indian percussion instruments like the Tabla and Mridangam.`},{q:`What determines the pitch of a sound?`,a:`The frequency of the wave; higher frequency results in a higher (shriller) pitch.`},{q:`What is 'Reverberation'?`,a:`The persistence of sound in a large hall due to multiple reflections, often managed by sound-absorbing materials.`}]},{title:`Reproduction: How Life Continues`,summary:`Exploring the biological mechanics of survival, from vegetative cloning in agriculture to the complex dance of human heredity.`,flashcards:[{front:`Vegetative Propagation`,back:`Asexual reproduction where new plants grow from parts like stems (cutting), roots, or leaves (Bryophyllum).`},{front:`Meiosis`,back:`A special cell division that reduces chromosome numbers by half to form haploid gametes (sperm/egg).`},{front:`Double Fertilisation`,back:`The process in plants where one male gamete fuses with the egg and another with the polar nuclei.`},{front:`Pollination`,back:`The transfer of pollen grains from the anther (male) to the stigma (female).`},{front:`Zygote vs Foetus`,back:`A zygote is the initial single-cell stage; a foetus is the developing human from the 9th week of pregnancy.`},{front:`Menstrual Cycle`,back:`A 28-day cycle of uterine lining preparation, ovulation (Day 14), and shedding (menstruation).`},{front:`Contraception`,back:`Methods to prevent pregnancy, including barriers (condoms), hormonal pills, and IUDs (Copper-T).`}],qna:[{q:`Why is genetic variation important in sexual reproduction?`,a:`It helps individuals adapt to changing environments, which is the driving force of evolution.`},{q:`What is the role of ASHA workers in India?`,a:`Community health workers who promote hygiene, immunisation, and maternal care in rural areas.`},{q:`Who pioneered India's first test-tube baby (IVF)?`,a:`Subhash Mukhopadhyay in 1978 (baby nicknamed 'Durga').`},{q:`How does the 'Syaahi' patch affect drum sounds?`,a:`It alters the membrane's vibration, creating rich harmonic overtones (studied by C.V. Raman).`},{q:`What is the law regarding prenatal sex determination in India?`,a:`It is strictly prohibited to prevent gender-based selective abortion and maintain societal balance.`}]},{title:`Patterns in Life: Diversity and Classification`,summary:`From the microscopic Monera to the majestic vertebrates of the Western Ghats, this module maps the tree of life.`,flashcards:[{front:`Biodiversity Hotspot`,back:`Regions like the Western Ghats or Himalayas with high species richness and endemic life.`},{front:`Five Kingdom Classification`,back:`Whittaker's system (1969): Monera, Protista, Fungi, Plantae, and Animalia.`},{front:`Binomial Nomenclature`,back:`Linnaeus's system for unique scientific names (Genus + Species), e.g., Mangifera indica.`},{front:`Arthropoda`,back:`The largest animal group; features jointed appendages and a hard exoskeleton (insects, crabs).`},{front:`Endemic Species`,back:`Species found only in a specific region, such as the Nilgiri tahr or Lion-tailed macaque.`},{front:`Angiosperms`,back:`Flowering plants where seeds are enclosed within fruits (the most diverse plant group).`},{front:`Three Domains`,back:`Modern classification based on DNA: Bacteria, Archaea, and Eukarya (Carl Woese).`}],qna:[{q:`What is the basis of Whittaker's classification?`,a:`Cell type (prokaryote/eukaryote), level of organisation, and mode of nutrition.`},{q:`How do Bryophytes differ from Thallophytes?`,a:`Bryophytes have a slightly differentiated body (mosses) and are the 'amphibians' of the plant kingdom.`},{q:`What is the role of 'Phumdis' in Manipur?`,a:`Unique floating grasslands in Loktak Lake that support the endangered Sangai (dancing deer).`},{q:`Who founded the Birbal Sahni Institute of Palaeosciences?`,a:`Birbal Sahni, an eminent scientist who studied fossil plants to trace life's history.`},{q:`Why is 'Monera' significant in Earth's history?`,a:`Ancient Cyanobacteria in this kingdom were among the first to produce oxygen, changing the atmosphere.`}]},{title:`Earth as a System: Energy, Matter, and Life`,summary:`The grand finale: integrating energy flows, planetary cycles, and the delicate balance of Earth's five spheres.`,flashcards:[{front:`Earth's Spheres`,back:`The Geosphere (rocks), Hydrosphere (water), Cryosphere (ice), Atmosphere (air), and Biosphere (life).`},{front:`Albedo`,back:`The measure of a surface's reflectivity; high for snow/ice (stays cool), low for oceans (absorbs heat).`},{front:`Solar Constant`,back:`The average solar energy received at the top of the atmosphere, approximately 1.4 kW/m².`},{front:`Biogeochemical Cycle`,back:`The continuous cycling of nutrients (C, N, O, H₂O) between living organisms and the environment.`},{front:`Eutrophication`,back:`Excess nutrients (nitrates/phosphates) in water causing algal blooms that deplete oxygen and kill fish.`},{front:`Greenhouse Effect`,back:`The trapping of re-radiated infrared heat by gases like CO₂, keeping Earth habitable but causing warming when excessive.`},{front:`Mission LiFE`,back:`An India-led initiative encouraging mindful, eco-friendly lifestyles to restore planetary balance.`}],qna:[{q:`Why is the ozone layer critical for the biosphere?`,a:`It absorbs harmful UV radiation in the stratosphere, protecting DNA and preventing skin/eye damage.`},{q:`How does deforestation affect the carbon cycle?`,a:`It reduces photosynthesis (CO₂ absorption) and releases stored carbon when trees are burnt or decay.`},{q:`What is the 'Urban Heat Island' effect?`,a:`Cities stay warmer than rural areas because concrete and asphalt absorb more solar radiation and retain heat.`},{q:`How do ocean currents regulate global climate?`,a:`They act as a conveyor belt, transporting heat from the equator to the poles (e.g., the North Atlantic Drift).`},{q:`Who was Anna Mani?`,a:`A pioneering Indian scientist who mapped solar insolation across India, laying the foundation for our solar energy future.`}]}]},English:{chapters:[{title:`How I Taught My Grandmother to Read`,summary:`A beautiful story about a twelve-year-old girl in north Karnataka who teaches her sixty-two-year-old grandmother, Krishtakka, to read the Kannada alphabet so she can independently read the novel Kashi Yatre.`,keyIdeas:[`Education is the ultimate tool for personal independence and self-reliance, regardless of age.`,`Determination and willpower can overcome any obstacle, including starting to learn at the age of sixty-two.`,`The relationship between a teacher and a student transcends familial hierarchy and age.`,`Traditional storytelling and serialized novels act as powerful cultural anchors in rural households.`],flashcards:[{front:`Ardent`,back:`Keen, passionate, or full of enthusiasm (e.g., an ardent desire).`},{front:`Savouring`,back:`Enjoying or tasting something to the absolute fullest.`},{front:`Taken aback`,back:`Surprised and completely shocked by something unexpected.`},{front:`Passed with flying colours`,back:`An idiom meaning to perform outstandingly and succeed brilliantly.`},{front:`Sink or swim`,back:`A binomial meaning to succeed or fail entirely by one's own efforts.`},{front:`Learn by heart`,back:`To completely memorize something so it can be repeated from memory.`}],qna:[{q:`Why did Krishtakka weep when the narrator returned from the wedding?`,a:`She felt dependent and helpless because she was unable to read the latest episode of Kashi Yatre in the Karmaveera magazine.`},{q:`Why did the grandmother touch her granddaughter's feet on Dassara?`,a:`She touched her feet as a mark of respect for a teacher, stating that one must respect a teacher irrespective of age and gender.`},{q:`What was the significance of the novel Kashi Yatre to the grandmother?`,a:`The protagonist of the novel desired to go to Kashi but sacrificed her savings to help an orphan girl marry. The grandmother identified deeply with this selfless struggle.`}]},{title:`Bharat Our Land`,summary:`A patriotic ode that celebrates India's majestic physical geography, rich spiritual heritage, sacred texts, and courageous historical figures.`,keyIdeas:[`India possesses an unparalleled synthesis of physical grandeur (Himalayas, Ganga) and deep spiritual wisdom (Upanishads).`,`The nation's legacy is built on the dual pillars of valor (gallant warriors) and wisdom (sacred sages).`,`A strong connection to cultural heritage and geography fosters unity and national pride.`],flashcards:[{front:`Peerless`,back:`Incomparable, unmatched, and having no equal anywhere on Earth.`},{front:`Hoary antiquity`,back:`The ancient, primeval past, stretching back to time immemorial.`},{front:`Himavant`,back:`The mighty Himalayan mountain range, symbolizing strength and permanence.`},{front:`Generous Ganga`,back:`Symbol of purity and natural grace, depicting India's life-giving river systems.`},{front:`Sanctified land`,back:`A land blessed, purified, and made sacred by ancient sages and historical leaders.`}],qna:[{q:`Why is India referred to as 'this sunny golden land'?`,a:`To symbolize its natural richness, warmth, glory, and agricultural abundance.`},{q:`What does the refrain 'she's peerless, let's praise her!' convey?`,a:`It reinforces absolute national pride and highlights India's unique standing in the world.`},{q:`Name the two prominent spiritual figures mentioned in the poem who enriched the land.`,a:`Gautama Buddha (who preached Dhamma) and the ancient sages who realized Brahma-knowledge.`}]},{title:`The Pot Maker`,summary:`Set in a traditional village, it tells the story of Sentila, a young girl determined to carry forward the ancient, laborious craft of pottery despite her mother's discouragement and the village council's interference, eventually finding her flow with the help of Aunt Onula.`,keyIdeas:[`Traditional skills and cultural crafts belong to the collective community, carrying historical legacy across generations.`,`Perseverance and intrinsic passion are essential when pursuing a creative vocation against practical obstacles.`,`Teaching requires patience and an understanding of the student's emotional state, as shown by Onula's success over Arenla's frustration.`],flashcards:[{front:`Pittance`,back:`A very small, insufficient amount of money received as income or wages.`},{front:`Deftly`,back:`Performing an action with high skill, speed, and cleverness.`},{front:`Malleable dough`,back:`Soft clay that is highly pliable and easily shaped without cracking.`},{front:`Momentous transition`,back:`An event or moment of grand significance that marks a major turning point.`},{front:`Profound revelation`,back:`A powerful, deep moment of realization or discovery.`},{front:`Symmetry`,back:`Perfect balance and matching proportions, as seen in the two neat rows of pots.`}],qna:[{q:`Why did Sentila's mother, Arenla, prefer that she learn weaving over pot making?`,a:`Weaving was cleaner, could be done indoors, took less time, and earned a handsome return compared to the tedious and low-paying labor of pot making.`},{q:`What did the village council remind Mesoba regarding traditional crafts?`,a:`That traditional crafts symbolize the culture and history of the community, do not belong to individuals, and must be passed down to anyone wishing to learn.`},{q:`How did Onula help Sentila find her confidence in shaping clay?`,a:`Onula taught her to relax, showed her how to shape clay when she was too tense, and gave her the quiet encouragement her mother couldn't offer.`}]},{title:`Gifts of Grace: Honouring Our Vocations`,summary:`A celebratory poem that honors the dignity of labor, profiling various skilled artisans and craftsmen—electricians, carpenters, cooks, shoemakers—and their role in forming societal identity.`,keyIdeas:[`The dignity of labor and respect for all vocations is vital for a harmonious society.`,`Every craftsperson's skill is an act of creation, linking math, art, and function.`,`The voice of one's vocation forms the core of personal and cultural identity.`],flashcards:[{front:`Myriad`,back:`Countless, innumerable, or existing in extremely large numbers.`},{front:`Hues`,back:`Shades or tints of colors that create visual variety and beauty.`},{front:`Affirming`,back:`Declaring with confidence, verifying, or validating the quality of something.`},{front:`Delicious singing`,back:`A sensory metaphor equating pleasing music to an enjoyable taste.`},{front:`Dignity of Labor`,back:`The philosophy that all types of jobs are respected equally, and no occupation is superior.`}],qna:[{q:`Explain the significance of the line 'The voice of their vocation is the voice of their identity.'`,a:`It highlights that a person's work is not just a source of income, but a fundamental expression of who they are and their place in the community.`},{q:`What does the carpenter create with mathematical precision?`,a:`The carpenter is admired for creating beautiful and functional things out of raw wood using logical, precise calculations.`},{q:`How does the poet use sensory imagery in this poem?`,a:`By using terms like 'delicious singing' for the cook, 'humming' for the electrician, and 'myriad hues' for the craftsperson's work to bring everyday activities to life.`}]},{title:`Winds of Change`,summary:`An exploration of the punkha (traditional hand fan) as a historical and cultural artifact, tracing its evolution from Ajanta paintings and royal courts to its modern status as a preserved traditional craft.`,keyIdeas:[`The design of traditional artifacts reflects the local geography, materials, and cultural heritage.`,`Industrial and technological progress runs the risk of displacing beautiful historical crafts and artisan livelihoods.`,`Preservation initiatives (like workshops and exhibitions) are crucial to sustain traditional craftspersons economically.`],flashcards:[{front:`Punkha origin`,back:`Originates from the word 'pankh', meaning bird feather, used for traditional hand fans.`},{front:`Appliqué hand fan`,back:`A Rajasthani fan made of pieces of fabric sewn onto another cloth with needlework.`},{front:`Zardozi hand fan`,back:`A Rajasthani hand fan decorated with glittering ornate gold and silver threadwork.`},{front:`Tal Patar Pankha`,back:`Bengali palm-leaf hand fans perpetually kept as staples in local households.`},{front:`Antiquity`,back:`The ancient past or great age, representing the long historical lineage of the fans.`},{front:`Encrusted`,back:`Covered or decorated with a hard, ornate layer of thread or beads.`}],qna:[{q:`Why does the author refer to punkhas as a 'culture' rather than just objects?`,a:`Because their design, materials (bamboo, leather, palm leaf, zardozi), and decorative styles reflect the distinct identity, history, and rituals of different Indian regions.`},{q:`How has the role of the punkha changed in modern India?`,a:`It has transitioned from a utility item for cooling royal courts and households into a decorative art piece and commercial handicraft that supports artisan livelihoods.`},{q:`What materials do Bengal artisans use to make delicate fans?`,a:`They use the milky-white spongy centre of the sola plant and palm leaves (Tal Patar Pankha).`}]},{title:`Canvas of Soil`,summary:`A lyric poem that frames the acts of gardening and farming as a form of art, comparing seeds to brushstrokes and the earth to a wide painter's canvas.`,keyIdeas:[`Nature and human creativity are deeply intertwined, with gardening serving as a living art form.`,`The Earth is a fertile canvas where life and aesthetic beauty coincide.`,`The cycle of planting seeds and waiting for spring reflects patience, hope, and growth.`],flashcards:[{front:`Palette`,back:`A board or tablet on which a painter mixes colors; in the poem, it represents the rich soil.`},{front:`Hue`,back:`A specific shade or tint of a color (e.g., spring's vibrant green, red, or blue).`},{front:`Brushstrokes of seeds`,back:`A metaphor comparing the act of planting seeds to a painter laying down paint.`},{front:`Canvas`,back:`The strong cloth used for oil paintings; in the poem, it represents the garden plot.`},{front:`Coincide`,back:`To happen at the same time or place; here, it marks the intersection of art and life.`}],qna:[{q:`How does the metaphor 'Brushstrokes of seeds' enhance the poem's theme?`,a:`It beautifully frames the physical, manual act of planting as a deliberate, creative gesture that will eventually paint the soil with colors.`},{q:`What is the deeper, allegorical meaning of the garden in the poem?`,a:`The garden can represent life's journey, the growth of dreams, and the harmony of diverse elements working together.`},{q:`What does the line 'Gardens become paintings still' suggest?`,a:`It captures the timeless, frozen beauty of a well-tended garden, which exists as a masterpiece of nature.`}]},{title:`Vitamin-M`,summary:`A heartwarming story about young Ravi, his forgetful yet brilliant grandfather, and a series of comical misadventures during a stealthy chase through town that ultimately strengthens their family bond.`,keyIdeas:[`Aging brings physical and memory challenges, but the emotional bonds of family remain deep and vital.`,`Respecting the dignity and independence of elders is just as important as ensuring their safety.`,`Love and caring are reciprocal; small acts of kindness and attention can heal generational gaps.`],flashcards:[{front:`Vitamin-M`,back:`A humorous name coined by Ravi's mother for a hypothetical memory-enhancing vitamin.`},{front:`Frail`,back:`Weak, delicate, or easily broken (often describing health or the elderly).`},{front:`Jauntily`,back:`Happily, confidently, and in a self-assured, lively manner.`},{front:`Deterred`,back:`Prevented or discouraged from doing something through fear or difficulty.`},{front:`Confront`,back:`To face someone directly, especially in a challenging or questioning way.`},{front:`Frantic`,back:`Highly excited, worried, or wild with fear and anxiety.`}],qna:[{q:`Why was Ravi's grandfather unhappy about living in the city flat?`,a:`He hated the crowded, noisy city life and missed the quietness of his small brick house in the town, where he could hear a leaf fall at dusk.`},{q:`How did Ravi find himself in a dilemma when his grandfather went out?`,a:`His grandfather would feel insulted if Ravi accompanied him, but his mother would be furious if she knew Grandpa was allowed to go out alone.`},{q:`What surprise did the grandfather have for Ravi and his mother?`,a:`He got them gift-wrapped parcels because he always gave gifts to every child in the house on his own birthday, which the mother had forgotten.`}]}]},Hindi:{chapters:[{title:`दो बैलों की कथा`,summary:`प्रेमचंद की यह अमर कहानी हीरा और मोती नामक दो बैलों की दोस्ती और उनके संघर्ष की गाथा है। गया के घर बंधक बनाए जाने पर दोनों बैल बार-बार भागकर अपने असली घर झूरी के पास लौट आते हैं। कांजीहौस में कैद होने के बाद मोती की वीरता और एक लड़की की मदद से वे आज़ादी पाते हैं। यह कहानी स्वतंत्रता, स्वाभिमान, मित्रता और पशुओं की बुद्धिमत्ता का सुंदर चित्रण है।`,keyIdeas:[`स्वतंत्रता सबसे बड़ी निधि है — बैल बार-बार कैद से भागकर यह सिद्ध करते हैं।`,`सच्ची मित्रता में एक-दूसरे के लिए निःस्वार्थ बलिदान होता है — हीरा और मोती का संबंध इसकी मिसाल है।`,`पशु भी भावनाएं और बुद्धि रखते हैं — वे प्रेम, क्रोध, स्वाभिमान को महसूस करते हैं।`,`अन्याय और अत्याचार के विरुद्ध विद्रोह उचित है — कांजीहौस में बैलों का विद्रोह इसका प्रतीक है।`,`देशभक्ति और स्वाधीनता का प्रतीक — यह कहानी भारतीय स्वतंत्रता संग्राम की पृष्ठभूमि में लिखी गई थी।`,`पराधीनता में जीना मृत्यु के समान है — बैल भूखे रहना पसंद करते हैं पर गुलामी नहीं।`],flashcards:[{front:`हीरा और मोती कौन थे?`,back:`झूरी काछी के दो बैल, जो परम मित्र थे और एक-दूसरे को बिना बोले ही समझते थे।`},{front:`झूरी काछी कौन थे?`,back:`हीरा-मोती के असली मालिक, जिनके घर को दोनों बैल अपना 'घर' मानते थे और बार-बार वहीं लौटते थे।`},{front:`गया के घर क्या हुआ?`,back:`झूरी ने बैलों को अपने साले गया के यहाँ भेजा, जहाँ उनसे अधिक काम लिया गया, कम खाना दिया गया और वे बंधे रहे।`},{front:`बैल पहली बार कब भागे?`,back:`गया के घर से — उन्होंने रातों-रात नाँद से मुँह उठाकर रस्सियाँ तुड़ाईं और सुबह होते-होते झूरी के द्वार पर थे।`},{front:`कांजीहौस क्या था?`,back:`वह स्थान जहाँ आवारा पशुओं को पकड़कर रखा जाता था — एक प्रकार की पशु-जेल।`},{front:`मोती ने दीवार कैसे गिराई?`,back:`मोती ने सींग मारकर कांजीहौस की कच्ची दीवार को तोड़ दिया ताकि सभी पशु भाग सकें।`},{front:`कांजीहौस में किसने बैलों की मदद की?`,back:`एक छोटी लड़की — जो कांजीहौस के मालिक की बेटी थी, उसने रात को चुपके से बैलों को भूसा और रोटियाँ खिलाईं।`},{front:`'साँड़' कौन था और उससे लड़ाई क्यों हुई?`,back:`एक विशालकाय साँड़ जिसने बैलों पर हमला किया। हीरा-मोती ने मिलकर उसे पराजित किया — मित्रता की जीत का प्रतीक।`},{front:`हीरा-मोती ने मटर के खेत क्यों खाए?`,back:`रास्ते में एक खेत में घुस गए और मटर खाने लगे — पहले नैतिक हिचक, फिर स्वाद के आगे झुक गए।`},{front:`कहानी का मूल संदेश क्या है?`,back:`स्वतंत्रता, स्वाभिमान और मित्रता सबसे बड़े मूल्य हैं। गुलामी से मुक्ति के लिए कोई भी कीमत चुकाई जा सकती है।`},{front:`प्रेमचंद`,back:`हिंदी साहित्य के महान कथाकार, जिन्हें 'उपन्यास सम्राट' कहा जाता है। 'दो बैलों की कथा' उनकी प्रसिद्ध कहानियों में से एक है।`},{front:`पराधीनता`,back:`दूसरों के अधीन रहना, गुलामी। कहानी में बैलों की कैद इसका प्रतीक है।`},{front:`गद्य खंड का अर्थ`,back:`पाठ्यपुस्तक का वह भाग जिसमें गद्य (prose) रचनाएँ — कहानी, निबंध आदि — शामिल होती हैं।`}],qna:[{q:`कहानी में बैलों की बुद्धिमत्ता को किस प्रकार दर्शाया गया है?`,a:`बैल बिना बोले एक-दूसरे की भावनाएं समझते हैं, रस्सियाँ तोड़कर घर का रास्ता खोजते हैं, साँड़ से मिलकर लड़ते हैं और सही-गलत की समझ रखते हैं।`},{q:`झूरी की पत्नी ने बैलों के घर लौटने पर क्या कहा?`,a:`झूरी की पत्नी ने व्यंग्य किया कि 'यहाँ क्यों नहीं आते, घर में जो रोटियाँ मिलती हैं' — यानी वह उनकी वापसी को संदेह की नजर से देख रही थी।`},{q:`हीरा और मोती में क्या अंतर था?`,a:`हीरा थोड़ा शांत और धैर्यशील था, जबकि मोती अधिक उग्र, साहसी और तुरंत प्रतिक्रिया देने वाला था।`},{q:`कांजीहौस में मोती ने दीवार क्यों गिराई पर खुद नहीं भागा?`,a:`मोती हीरा को अकेला नहीं छोड़ना चाहता था, क्योंकि हीरा की टाँगें बंधी थीं। यह उनकी गहरी मित्रता का प्रमाण है।`},{q:`कहानी में साँड़ से लड़ाई का क्या प्रतीकात्मक महत्व है?`,a:`साँड़ शक्तिशाली अत्याचारी का प्रतीक है। दोनों बैलों का मिलकर उसे हराना यह सिखाता है कि एकता में बल है।`},{q:`लड़की ने बैलों को खाना क्यों खिलाया?`,a:`उस मासूम बच्ची के मन में दया भाव था। उसकी खुद की माँ नहीं थी और सौतेली माँ उसे सताती थी — वह दूसरों का दुख समझती थी।`},{q:`रामचंद्र शुक्ल और निराला के कथन क्या बताते हैं?`,a:`शुक्ल जी के अनुसार आधुनिक काल में गद्य का उदय सबसे प्रधान साहित्यिक घटना है। निराला के अनुसार गद्य संघर्षशील जीवन की भाषा है।`},{q:`प्रेमचंद की कहानी की परिभाषा क्या है?`,a:`प्रेमचंद के अनुसार कहानी ऐसी रचना है जिसमें जीवन के किसी एक अंग या मनोभाव को प्रदर्शित करना लेखक का उद्देश्य होता है।`}]},{title:`ल्हासा की ओर`,summary:`राहुल सांकृत्यायन द्वारा लिखित यह यात्रा-वृत्तांत तिब्बत की कठिन यात्रा का वर्णन करता है। बौद्ध धर्म और संस्कृति से जुड़े स्थानों की खोज करते हुए लेखक की यात्रा रोमांच और साहस से भरी है।`,keyIdeas:[`साहस और जिज्ञासा अज्ञात दुनिया को जानने की प्रेरणा देती है।`,`यात्रा केवल स्थान बदलना नहीं, आत्मा का विस्तार है।`,`विभिन्न संस्कृतियों और परंपराओं को समझना हमें व्यापक दृष्टि देता है।`],flashcards:[{front:`राहुल सांकृत्यायन`,back:`हिंदी के प्रसिद्ध यात्री-लेखक, जिन्हें 'महापंडित' कहा जाता है। उन्होंने तिब्बत की कई यात्राएं की।`},{front:`ल्हासा`,back:`तिब्बत की राजधानी, बौद्ध धर्म का पवित्र केंद्र।`},{front:`यात्रा-वृत्तांत`,back:`यात्रा के अनुभवों और घटनाओं का साहित्यिक वर्णन, गद्य की एक विधा।`}],qna:[{q:`लेखक ने तिब्बत की यात्रा क्यों की?`,a:`बौद्ध धर्म से संबंधित ग्रंथों और स्थानों की खोज के लिए, और अज्ञात प्रदेशों को जानने की जिज्ञासा से।`},{q:`तिब्बत की यात्रा में क्या कठिनाइयाँ थीं?`,a:`दुर्गम पहाड़ी रास्ते, भाषा की बाधा, कठोर मौसम और विदेशियों के प्रवेश पर प्रतिबंध।`}]},{title:`उपभोक्तावाद की संस्कृति`,summary:`श्यामाचरण दुबे द्वारा लिखित यह निबंध आधुनिक उपभोक्तावादी संस्कृति की आलोचना करता है और बताता है कि किस प्रकार विज्ञापन और बाजारवाद हमारी जीवनशैली और मूल्यों को प्रभावित कर रहे हैं।`,keyIdeas:[`उपभोक्तावाद मानव को वस्तुओं का दास बना देता है।`,`विज्ञापन कृत्रिम जरूरतें पैदा करते हैं और लोगों को भ्रमित करते हैं।`,`पारंपरिक मूल्यों और सादगी को बाजारवाद से बचाना जरूरी है।`],flashcards:[{front:`उपभोक्तावाद`,back:`वह प्रवृत्ति जिसमें वस्तुओं का अत्यधिक उपभोग जीवन का लक्ष्य बन जाता है।`},{front:`बाजारवाद`,back:`वह व्यवस्था जहाँ बाजार की ताकतें समाज और संस्कृति को नियंत्रित करती हैं।`},{front:`विज्ञापन का प्रभाव`,back:`विज्ञापन लोगों में नई इच्छाएं जगाते हैं और उन्हें अनावश्यक चीजें खरीदने के लिए प्रेरित करते हैं।`}],qna:[{q:`उपभोक्तावादी संस्कृति समाज को कैसे प्रभावित करती है?`,a:`यह भौतिकता को बढ़ावा देती है, रिश्तों को कमजोर करती है और पारंपरिक मूल्यों को नष्ट करती है।`},{q:`लेखक किस विकल्प का सुझाव देते हैं?`,a:`सादा जीवन, पर्यावरण के अनुकूल उपभोग और मानवीय मूल्यों को प्राथमिकता देना।`}]},{title:`साखियाँ एवं सबद`,summary:`कबीरदास की साखियाँ और मीराबाई के पद — भक्ति काल की अमूल्य धरोहर। कबीर ने गुरु महिमा, सच्चे ज्ञान और आडंबर के विरोध में निर्गुण भक्ति के पद रचे, जबकि मीरा ने श्रीकृष्ण के प्रति अपने समर्पण को गीतों में ढाला।`,keyIdeas:[`कबीर की साखियाँ जीवन की व्यावहारिक सच्चाइयों पर आधारित हैं।`,`गुरु का महत्व ज्ञान प्राप्ति में सर्वोपरि है।`,`मीरा का भक्ति-प्रेम लोक-लाज से परे निःस्वार्थ समर्पण है।`,`भक्ति काल में धार्मिक आडंबर का विरोध हुआ और सच्ची भक्ति पर जोर दिया गया।`],flashcards:[{front:`साखी`,back:`कबीर के दोहे जिनमें जीवन की सरल शिक्षाएं हैं। 'साखी' शब्द 'साक्षी' से बना है।`},{front:`सबद (शब्द)`,back:`कबीर के गीत-पद जिन्हें संगीत के साथ गाया जाता था।`},{front:`निर्गुण भक्ति`,back:`निराकार ईश्वर की उपासना — कबीर इस परंपरा के प्रमुख कवि थे।`},{front:`मीराबाई`,back:`16वीं सदी की राजस्थानी कवयित्री जो श्रीकृष्ण की परम भक्त थीं।`},{front:`भक्ति काल`,back:`हिंदी साहित्य का स्वर्णकाल (14वीं-17वीं सदी), जिसमें कबीर, मीरा, तुलसी, सूर जैसे कवि हुए।`}],qna:[{q:`कबीर के अनुसार गुरु का क्या महत्व है?`,a:`कबीर ने गुरु को ईश्वर से भी बड़ा माना है — गुरु ही अज्ञान का अंधकार दूर करके ज्ञान का प्रकाश देते हैं।`},{q:`मीरा के पदों में किस भाव की प्रधानता है?`,a:`मीरा के पदों में माधुर्य भाव की प्रधानता है — वे श्रीकृष्ण को अपना प्रियतम मानकर उनसे विरह और मिलन की कामना करती हैं।`},{q:`कबीर ने किन रूढ़ियों का विरोध किया?`,a:`कबीर ने जाति-पाँति, धार्मिक कर्मकांड, मूर्तिपूजा और बाहरी दिखावे का विरोध किया।`}]}]}}}